class BankAccount {
  owner: string;
  balance: number;
  currency: string;

  constructor(owner: string, initialBalance: number, currency = "USD") {
    this.owner = owner;
    this.balance = initialBalance;
    this.currency = currency;
  }

  describe(): string {
    return `${this.owner}: ${this.currency} ${this.balance.toFixed(2)}`;
  }
}

const account = new BankAccount("Alice", 1000);
const euroAccount = new BankAccount("Bob", 500, "EUR");

console.log(account.describe());
console.log(euroAccount.describe());

class BankAccount {
  constructor(
    public readonly owner: string,
    private balance: number,
    public readonly currency: string = "USD"
  ) {}

  deposit(amount: number): void {
    if (amount <= 0) throw new Error("Amount must be positive");
    this.balance += amount;
  }

  getBalance(): number {
    return this.balance;
  }

  describe(): string {
    return `${this.owner}: ${this.currency} ${this.balance.toFixed(2)}`;
  }
}

const acc = new BankAccount("Carol", 500);
acc.deposit(250);
acc.deposit(100);
// acc.balance = 0;  // ← Error: 'balance' is private
console.log(acc.describe());
console.log(`Balance: ${acc.getBalance()}`);

class Employee {
