class Temperature {
  private _celsius: number;

  constructor(celsius: number) {
    this._celsius = celsius;
  }

  get celsius(): number {
    return this._celsius;
  }

  set celsius(value: number) {
    if (value < -273.15) throw new Error("Below absolute zero!");
    this._celsius = value;
  }

  get fahrenheit(): number {
    return this._celsius * 9 / 5 + 32;
  }

  get kelvin(): number {
    return this._celsius + 273.15;
  }
}

const temp = new Temperature(100);
console.log(`${temp.celsius}°C = ${temp.fahrenheit}°F = ${temp.kelvin}K`);

temp.celsius = 0;
console.log(`${temp.celsius}°C = ${temp.fahrenheit}°F = ${temp.kelvin}K`);

temp.celsius = 37;
console.log(`Body temp: ${temp.fahrenheit}°F`);

class User {
  private static nextId = 1;
  private static instances = 0;

  public readonly id: number;
  public createdAt: string;

  constructor(
    public readonly name: string,
    public readonly email: string
  ) {
    this.id = User.nextId++;
    this.createdAt = new Date().toISOString().slice(0, 10);
    User.instances++;
  }

  static getCount(): number {
    return User.instances;
  }

  static createAdmin(name: string): User {
    return new User(name, `${name.toLowerCase()}@admin.company.com`);
  }

  toString(): string {
    return `User#${this.id}: ${this.name} (${this.email})`;
  }
}

const u1 = new User("Alice", "alice@co.com");
const u2 = User.createAdmin("Bob");
const u3 = new User("Carol", "carol@co.com");

console.log(u1.toString());
console.log(u2.toString());
console.log(u3.toString());
console.log(`Total users: ${User.getCount()}`);

