abstract class Report {
  constructor(protected title: string) {}

  // Must be implemented by subclasses
  abstract generateContent(): string[];
  abstract getFormat(): string;

  // Shared implementation — subclasses inherit this
  render(): void {
    console.log(`=== ${this.title} (${this.getFormat()}) ===`);
    for (const line of this.generateContent()) {
      console.log(line);
    }
  }
}

class SalesReport extends Report {
  constructor(private revenue: number, private deals: number) {
    super("Sales Report");
  }

  getFormat(): string { return "PDF"; }
  generateContent(): string[] {
    return [
      `Revenue:    $${this.revenue.toLocaleString()}`,
      `Deals:      ${this.deals}`,
      `Avg deal:   $${Math.round(this.revenue / this.deals).toLocaleString()}`,
    ];
  }
}

const report = new SalesReport(84320, 42);
report.render();

interface Storage<T> {
  get(key: string): T | undefined;
  set(key: string, value: T): void;
  delete(key: string): boolean;
  has(key: string): boolean;
  size(): number;
}

class MemoryStorage<T> implements Storage<T> {
  private store = new Map<string, T>();

  get(key: string): T | undefined      { return this.store.get(key);    }
  set(key: string, value: T): void      { this.store.set(key, value);    }
  delete(key: string): boolean          { return this.store.delete(key); }
  has(key: string): boolean             { return this.store.has(key);    }
  size(): number                        { return this.store.size;        }
}

const cache = new MemoryStorage<string>();
cache.set("user:1", "Alice");
cache.set("user:2", "Bob");
cache.set("user:3", "Carol");

console.log(`Has user:1: ${cache.has("user:1")}`);
console.log(`Get user:2: ${cache.get("user:2")}`);
console.log(`Size: ${cache.size()}`);
cache.delete("user:1");
console.log(`After delete, size: ${cache.size()}`);

class SecureVault {
  #secretKey: string;    // truly private — can't be accessed outside
  private label: string; // compile-time private only

  constructor(key: string, label: string) {
    this.#secretKey = key;
    this.label = label;
  }

  verify(input: string): boolean {
    return input === this.#secretKey;
  }

  describe(): string {
    return `Vault: ${this.label} (key hidden)`;
  }
}

const vault = new SecureVault("super-secret-123", "Main Vault");

console.log(vault.describe());
console.log(`Correct key: ${vault.verify("super-secret-123")}`);
console.log(`Wrong key:   ${vault.verify("guessed-key")}`);

// (vault as any).label works at runtime — 'private' is compile-time only
// (vault as any).#secretKey is a runtime syntax error — # is truly private

type Constructor<T = object> = new (...args: unknown[]) => T;

function Timestamped<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    createdAt = new Date().toISOString().slice(0, 10);
    updatedAt = new Date().toISOString().slice(0, 10);

    touch(): void {
      this.updatedAt = new Date().toISOString().slice(0, 10);
    }
  };
}

function Serializable<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    toJSON(): string {
      return JSON.stringify(this);
    }
  };
}

class User {
  constructor(public name: string, public email: string) {}
}

const TimestampedSerializableUser = Serializable(Timestamped(User));

const user = new TimestampedSerializableUser("Alice", "alice@co.com");
console.log(`Name: ${user.name}`);
console.log(`Created: ${user.createdAt}`);
console.log(`JSON keys: ${Object.keys(JSON.parse(user.toJSON())).join(", ")}`);

// Manual decorator simulation (without experimental flag)
function sealed(constructor: Function): void {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

function log(target: object, key: string, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value as (...args: unknown[]) => unknown;
  descriptor.value = function (...args: unknown[]) {
    console.log(`Calling ${key}(${args.map(a => JSON.stringify(a)).join(", ")})`);
    const result = original.apply(this, args);
    console.log(`  → ${JSON.stringify(result)}`);
    return result;
  };
  return descriptor;
}

