type EventMap = Record<string, unknown>;

class TypedEventEmitter<Events extends EventMap> {
  private handlers = new Map<keyof Events, Array<(payload: unknown) => void>>();

  on<K extends keyof Events>(event: K, handler: (payload: Events[K]) => void): this {
    const existing = this.handlers.get(event) ?? [];
    existing.push(handler as (payload: unknown) => void);
    this.handlers.set(event, existing);
    return this;
  }

  emit<K extends keyof Events>(event: K, payload: Events[K]): void {
    const handlers = this.handlers.get(event) ?? [];
    for (const handler of handlers) handler(payload);
  }
}

interface AppEvents {
  login:  { userId: number; timestamp: string };
  logout: { userId: number };
  error:  { message: string; code: number };
}

const emitter = new TypedEventEmitter<AppEvents>();

emitter.on("login",  e => console.log(`User ${e.userId} logged in`));
emitter.on("logout", e => console.log(`User ${e.userId} logged out`));
emitter.on("error",  e => console.log(`Error ${e.code}: ${e.message}`));

emitter.emit("login",  { userId: 42, timestamp: "2024-01-15" });
emitter.emit("error",  { message: "Rate limit exceeded", code: 429 });
emitter.emit("logout", { userId: 42 });

class Stack<T> {
  private items: T[] = [];

  push(item: T): void {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }

  peek(): T | undefined {
    return this.items[this.items.length - 1];
  }

  isEmpty(): boolean {
    return this.items.length === 0;
  }

  get size(): number {
    return this.items.length;
  }
}

const numStack = new Stack<number>();
numStack.push(1);
numStack.push(2);
numStack.push(3);

console.log(`Size: ${numStack.size}`);
console.log(`Peek: ${numStack.peek()}`);
console.log(`Pop: ${numStack.pop()}`);
console.log(`Pop: ${numStack.pop()}`);
console.log(`Size after pops: ${numStack.size}`);

